zigbee_status_t zigbee_commission_device(void) {
    printf("\n========================================\n");
    printf("Zigbee Smart Light Bulb Commissioning\n");
    printf("========================================\n\n");
    
    zigbee_status_t status;
    
    status = zigbee_stack_init();
    if (status != ZIGBEE_STATUS_SUCCESS) {
        printf("[ERROR] Stack initialization failed\n");
        return status;
    }
    
    printf("\n[COMMISSIONING] Step 1: Network Discovery\n");
    network_descriptor_t networks[10];
    uint8_t network_count = 0;
    
    status = zigbee_network_discovery(networks, &network_count, 10);
    if (status != ZIGBEE_STATUS_SUCCESS || network_count == 0) {
        printf("[ERROR] No networks found\n");
        return ZIGBEE_STATUS_NO_NETWORK;
    }
    
    printf("\n[COMMISSIONING] Step 2: Select Network\n");
    network_descriptor_t *selected_network = NULL;
    for (uint8_t i = 0; i < network_count; i++) {
        if (networks[i].permit_join) {
            selected_network = &networks[i];
            printf("[COMMISSIONING] Selected network with PAN ID 0x%04X (PermitJoin enabled)\n", 
                   selected_network->pan_id);
            break;
        }
    }
    
    if (!selected_network) {
        printf("[ERROR] No joinable networks found\n");
        return ZIGBEE_STATUS_ERROR;
    }
    
    printf("\n[COMMISSIONING] Step 3: Join Network\n");
    uint8_t retry_count = 0;
    while (retry_count < ZIGBEE_MAX_RETRIES) {
        status = zigbee_join_network(selected_network);
        if (status == ZIGBEE_STATUS_SUCCESS) {
            break;
        }
        
        retry_count++;
        printf("[COMMISSIONING] Join attempt %d failed, retrying...\n", retry_count);
    }
    
    if (status != ZIGBEE_STATUS_SUCCESS) {
        printf("[ERROR] Failed to join network after %d attempts\n", ZIGBEE_MAX_RETRIES);
        return status;
    }
    
    printf("\n[COMMISSIONING] Step 4: Post-Join Configuration\n");
    network_info_t net_info;
    zigbee_get_network_info(&net_info);
    
    printf("[COMMISSIONING] Device commissioned successfully!\n");
    printf("  - Short Address: 0x%04X\n", net_info.short_address);
    printf("  - PAN ID: 0x%04X\n", net_info.pan_id);
    printf("  - Channel: %d\n", net_info.channel);
    printf("  - State: %s\n", net_info.state == NETWORK_STATE_JOINED ? "JOINED" : "UNKNOWN");
    
    return ZIGBEE_STATUS_SUCCESS;
}

